const trades = $input.all().map(i => i.json);
const wh = $('Webhook').first().json;
return [{ json: { trades, sheet_id: wh.body.sheet_id, email: wh.body.email || '' } }];

// Construir config desde filas campo/valor
const configRows = $input.all().map(i => i.json || {});
const trades = $('Preparar Datos').first().json.trades || [];

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function parseNumber(value) {
  if (value === null || value === undefined) return NaN;

  const s = String(value).trim().toUpperCase();
  if (!s) return NaN;
  if (s === 'BE') return 0;

  const normalized = s
    .replace('%', '')
    .replace(/\s/g, '')
    .replace(',', '.')
    .replace('+', '');

  const n = parseFloat(normalized);
  return Number.isFinite(n) ? n : NaN;
}

// Leer config de forma robusta
const config = {};

for (const row of configRows) {
  const entries = Object.entries(row);
  const lowerRow = Object.fromEntries(
    entries.map(([k, v]) => [String(k).toLowerCase(), v])
  );

  const campo = lowerRow.campo ?? lowerRow.field ?? Object.values(row)[0];
  const valor = lowerRow.valor ?? lowerRow.value ?? Object.values(row)[1];

  if (campo && valor !== undefined) {
    config[String(campo).trim().toLowerCase()] = valor;
  }

  // También soporta config como columnas directas
  for (const [k, v] of Object.entries(lowerRow)) {
    if (v !== undefined && v !== null && String(v).trim() !== '') {
      if (!config[k]) config[k] = v;
    }
  }
}

const mes = String(config.mes || 'MES').toUpperCase();
const anio = String(config.anio || new Date().getFullYear());

// Calcular total si viene vacío o mal cargado
const computedTotal = trades.reduce((acc, t) => {
  const resultado = t.resultado ?? t.Resultado ?? '';
  const n = parseNumber(resultado);
  return acc + (Number.isFinite(n) ? n : 0);
}, 0);

let totalRaw = config.total;

if (
  totalRaw === undefined ||
  totalRaw === null ||
  String(totalRaw).trim() === '' ||
  String(totalRaw).trim().toLowerCase() === 'total'
) {
  totalRaw = `${computedTotal >= 0 ? '+' : ''}${computedTotal.toFixed(2)}%`;
}

const total = String(totalRaw);

// Ajustes dinámicos según cantidad de trades
const rowCount = trades.length;
let titleSize = 52;
let bodySize = 16;
let rowPaddingY = 9;
let headerMargin = 24;
let totalSize = 22;
let logoHeight = 34;

if (rowCount > 18) {
  titleSize = 46;
  bodySize = 14;
  rowPaddingY = 7;
  headerMargin = 18;
  totalSize = 20;
  logoHeight = 30;
}

if (rowCount > 24) {
  titleSize = 40;
  bodySize = 12;
  rowPaddingY = 5;
  headerMargin = 14;
  totalSize = 18;
  logoHeight = 28;
}

// URL del logo
const logoUrl = 'https://raw.githubusercontent.com/Dtolosag/proyecto-m71/main/assets/logo-m71.png';

// Solo renderiza el bloque si hay logo
const logoHtml = logoUrl
  ? `<div class="logo-sec">
       <img src="${logoUrl}" alt="M71 Trading" onerror="this.parentElement.style.display='none'">
     </div>`
  : '';

// Generar filas
const rowsHtml = trades.map(t => {
  const fecha = escapeHtml(t.fecha ?? t.Fecha ?? '');
  const activo = escapeHtml(t.activo ?? t.Activo ?? '');
  const tipo = escapeHtml(t.tipo ?? t.Tipo ?? '');
  const resultadoRaw = String(t.resultado ?? t.Resultado ?? '');
  const resultado = escapeHtml(resultadoRaw);

  let cls = '';
  const num = parseNumber(resultadoRaw);

  if (String(resultadoRaw).trim().toUpperCase() === 'BE') cls = '';
  else if (Number.isFinite(num) && num > 0) cls = 'pos';
  else if (Number.isFinite(num) && num < 0) cls = 'neg';

  return `<tr>
    <td>${fecha}</td>
    <td>${activo}</td>
    <td>${tipo}</td>
    <td class="${cls}">${resultado}</td>
  </tr>`;
}).join('');

const totalNum = parseNumber(total);
const totalCls = totalNum > 0 ? 'pos' : totalNum < 0 ? 'neg' : '';

const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Reporte M71</title>
<style>
*, *::before, *::after {
  box-sizing: border-box;
}

@page {
  size: A4;
  margin: 0;
}

html, body {
  margin: 0;
  padding: 0;
  background: #0d0d0d;
  color: #ffffff;
  font-family: Impact, "Arial Narrow", Arial, sans-serif;
  -webkit-print-color-adjust: exact;
  print-color-adjust: exact;
}

body {
  width: 100%;
}

.page {
  width: 100%;
  background: #0d0d0d;
  padding: 30px 34px 4px;
}

.header {
  text-align: center;
  margin-bottom: ${headerMargin}px;
}

.t1, .t2 {
  display: block;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 2px;
  line-height: 0.95;
  font-size: ${titleSize}px;
}

.t1 {
  color: #ffffff;
}

.t2 {
  color: #3dff50;
}

table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

colgroup col:nth-child(1) { width: 20%; }
colgroup col:nth-child(2) { width: 28%; }
colgroup col:nth-child(3) { width: 28%; }
colgroup col:nth-child(4) { width: 24%; }

thead th {
  background: #191919;
  color: #8a8a8a;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  padding: 9px 8px;
  text-align: center;
  border-bottom: 1px solid #2e2e2e;
}

tbody tr {
  border-bottom: 1px solid #1e1e1e;
  break-inside: avoid;
  page-break-inside: avoid;
}

tbody td {
  padding: ${rowPaddingY}px 8px;
  text-align: center;
  font-size: ${bodySize}px;
  font-weight: 700;
  color: #ffffff;
  word-wrap: break-word;
}

.pos {
  color: #3dff50;
}

.neg {
  color: #ff4040;
}

.total-sec,
.logo-sec {
  break-inside: avoid;
  page-break-inside: avoid;
}

.total-sec {
  margin-top: 8px;
  width: 100%;
  padding-top: 10px;
  border-top: 1px solid #2a2a2a;
  text-align: center;
}

.t-label {
  font-size: ${totalSize}px;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: #ffffff;
}

.t-val {
  font-size: ${totalSize}px;
  font-weight: 900;
  margin-left: 10px;
}

.logo-sec {
  margin-top: 2px;
  text-align: center;
}

.logo-sec img {
  height: ${logoHeight}px;
  max-width: 180px;
  width: auto;
  display: inline-block;
}

.empty-state {
  padding: 18px 10px;
  text-align: center;
  color: #b0b0b0;
  font-size: 14px;
  border-bottom: 1px solid #1e1e1e;
}
</style>
</head>
<body>
  <div class="page">
    <div class="header">
      <span class="t1">Resultados</span>
      <span class="t2">${escapeHtml(mes)} ${escapeHtml(anio)}</span>
    </div>

    <table>
      <colgroup>
        <col><col><col><col>
      </colgroup>
      <thead>
        <tr>
          <th>Fecha</th>
          <th>Activo Operado</th>
          <th>Tipo de Operación</th>
          <th>Resultado (%)</th>
        </tr>
      </thead>
      <tbody>
        ${rowsHtml || `<tr><td colspan="4" class="empty-state">Sin trades para mostrar</td></tr>`}
      </tbody>
    </table>

    <div class="total-sec">
      <span class="t-label">Total ${escapeHtml(mes)}:</span>
      <span class="t-val ${totalCls}">${escapeHtml(total)}</span>
    </div>

    ${logoHtml}
  </div>
</body>
</html>`;

const buf = Buffer.from(html, 'utf-8');

return [{
  json: { mes, anio, total },
  binary: {
    htmlFile: {
      data: buf.toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html',
      fileSize: buf.length
    }
  }
}];

const pdf = $input.first().binary.pdfData;

return [
  {
    json: {},
    binary: {
      data: pdf
    }
  }
];
